async function main() {
  const specialties = await prisma.specialty.findMany({ select: { id: true, slug: true } });
  const speId = new Map(specialties.map((s) => [s.slug, s.id]));

  let exOk = 0;
  let exMissingSpe: string[] = [];
  for (const e of EXAMS) {
    const specialtyId = speId.get(e.specialty) ?? null;
    if (!specialtyId) exMissingSpe.push(`${e.slug} → ${e.specialty}`);
    await prisma.medicalExam.upsert({
      where: { slug: e.slug },
      update: {}, // idempotent : ne pas écraser d'éventuelles corrections manuelles
      create: {
        slug: e.slug, name: e.name, nameAr: e.nameAr, category: e.category,
        shortAnswer: e.shortAnswer, shortAnswerAr: e.shortAnswerAr,
        indications: e.indications, indicationsAr: e.indicationsAr,
        procedure: e.procedure, procedureAr: e.procedureAr,
        preparation: e.preparation ?? null,
        precautions: e.precautions ?? null,
        durationMin: e.durationMin ?? null, priceMin: e.priceMin ?? null, priceMax: e.priceMax ?? null,
        reimbursement: e.reimbursement ?? null, reimbursementAr: e.reimbursementAr ?? null,
        synonyms: e.synonyms, faqJson: e.faqJson, sources: e.sources,
        specialtyId,
        status: "PUBLISHED",
        reviewedAt: null, arReviewedAt: null, // YMYL : noindex jusqu'à relecture
      },
    });
    exOk++;
  }

  let trOk = 0;
  let trMissingSpe: string[] = [];
  for (const t of TREATMENTS) {
    const specialtyId = speId.get(t.specialty) ?? null;
    if (!specialtyId) trMissingSpe.push(`${t.slug} → ${t.specialty}`);
    await prisma.treatment.upsert({
      where: { slug: t.slug },
      update: {},
      create: {
        slug: t.slug, name: t.name, nameAr: t.nameAr, category: t.category,
        shortAnswer: t.shortAnswer, shortAnswerAr: t.shortAnswerAr,
        options: t.options, optionsAr: t.optionsAr,
        duration: t.duration ?? null,
        sideEffects: t.sideEffects ?? null,
        redFlags: t.redFlags ?? null,
        whenToConsult: t.whenToConsult ?? null, whenToConsultAr: t.whenToConsultAr ?? null,
        synonyms: t.synonyms, faqJson: t.faqJson, sources: t.sources,
        specialtyId,
        status: "PUBLISHED",
        reviewedAt: null, arReviewedAt: null,
      },
    });
    trOk++;
  }

  console.log(`✓ Examens seedés : ${exOk}/${EXAMS.length}`);
  if (exMissingSpe.length) console.log(`  ⚠ spécialité introuvable (specialtyId=null) : ${exMissingSpe.join(", ")}`);
  console.log(`✓ Traitements seedés : ${trOk}/${TREATMENTS.length}`);
  if (trMissingSpe.length) console.log(`  ⚠ spécialité introuvable (specialtyId=null) : ${trMissingSpe.join(", ")}`);
  console.log("ℹ Tous en NOINDEX (reviewedAt=null). Après relecture : scripts/exams-approve.ts / treatments-approve.ts");
}

main().finally(() => prisma.$disconnect());
